	const FALLBACK_ICON = `<svg viewBox="0 0 24 24" class="w-5 h-5 text-base-content" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M18 13a6 6 0 0 1-6 5 6 6 0 0 1-6-5h12z"/><line x1="9" y1="9" x2="9.01" y2="9"/><line x1="15" y1="9" x2="15.01" y2="9"/></svg>`;

	function getLinkIcon(label: string): string {
		return LINK_ICONS[label] || FALLBACK_ICON;
	}
</script>

<script lang="ts">
	import type { ExternalLink } from '$lib/types';

	interface Props {
		links: ExternalLink[];
	}

	let { links }: Props = $props();

	// Client-side detection mirrors backend _PLATFORM_PATTERNS for cache resilience.
	// When backend has correct categories, these act as a safety net for stale cached data.
	const PLATFORM_PATTERNS: [string, string, string][] = [
		['spotify.com', 'Spotify', 'music'],
		['music.apple.com', 'Apple Music', 'music'],
		['youtube.com', 'YouTube', 'music'],
		['youtu.be', 'YouTube', 'music'],
		['bandcamp.com', 'Bandcamp', 'music'],
		['soundcloud.com', 'SoundCloud', 'music'],
		['deezer.com', 'Deezer', 'music'],
		['tidal.com', 'Tidal', 'music'],
		['amazon.com', 'Amazon', 'music'],
		['instagram.com', 'Instagram', 'social'],
		['twitter.com', 'Twitter', 'social'],
		['//x.com', 'Twitter', 'social'],
		['facebook.com', 'Facebook', 'social'],
		['last.fm', 'Last.fm', 'info'],
		['wikipedia.org', 'Wikipedia', 'info']
	];

	const ALLOWED_LABELS = new Set([
		'Spotify',
		'Apple Music',
		'YouTube',
		'Bandcamp',
		'SoundCloud',
		'Deezer',
		'Tidal',
		'Amazon',
		'Instagram',
		'Twitter',
		'Facebook',
		'Official Website',
		'Wikipedia',
		'Last.fm'
	]);

	function detectPlatform(url: string, type: string): [string, string] | null {
		const lower = url.toLowerCase();
		for (const [pattern, label, category] of PLATFORM_PATTERNS) {
			if (lower.includes(pattern)) return [label, category];
		}
		if (type === 'official homepage') return ['Official Website', 'info'];
		return null;
	}

	const CATEGORY_ORDER = ['music', 'social', 'info'] as const;

	const CATEGORY_LABELS: Record<string, string> = {
		music: 'Listen',
		social: 'Social',
		info: 'Info'
	};

	let groupedLinks = $derived.by(() => {
		const groups: Record<string, ExternalLink[]> = {};
		// eslint-disable-next-line svelte/prefer-svelte-reactivity
		const seen = new Set<string>();

		for (const link of links) {
			const detected = detectPlatform(link.url, link.type);
			const label = detected ? detected[0] : link.label;
			const category = detected ? detected[1] : (link.category ?? 'other');

			if (!ALLOWED_LABELS.has(label) || seen.has(label)) continue;
			seen.add(label);

			const resolved = { ...link, label, category };
			if (!groups[category]) groups[category] = [];
			groups[category].push(resolved);
		}

		return CATEGORY_ORDER.filter((c) => groups[c]?.length).map((c) => ({
			category: c,
			label: CATEGORY_LABELS[c] || c,
			links: groups[c]
		}));
	});
</script>

{#if groupedLinks.length > 0}
	<div class="flex flex-wrap items-center gap-x-6 gap-y-3 mt-4">
		{#each groupedLinks as group, i (group.category)}
			{#if i > 0}
				<div class="hidden sm:block w-px h-6 bg-base-content/20"></div>
			{/if}
			<div class="flex items-center gap-2">
				<span class="text-xs font-semibold uppercase tracking-widest text-base-content/70 mr-1">
					{group.label}
				</span>
				{#each group.links as link (link.type)}
					<a
						href={link.url}
						target="_blank"
						rel="noopener noreferrer"
						class="btn btn-ghost btn-circle btn-md tooltip tooltip-bottom"
						data-tip={link.label}
					>
						<!-- eslint-disable-next-line svelte/no-at-html-tags -->
						{@html getLinkIcon(link.label)}
					</a>
				{/each}
			</div>
		{/each}
	</div>
{/if}
